157	int main() {
158	    std::ios_base::sync_with_stdio(false);
159	    std::cin.tie(NULL);
160	
161	    program_start_time = std::chrono::steady_clock::now();
162	    uint64_t random_seed = std::chrono::duration_cast<std::chrono::nanoseconds>(std::chrono::steady_clock::now().time_since_epoch()).count();
163	    rng_engine.seed(random_seed);
164	
165	    std::cin >> N_items_global >> D_groups_global >> Q_total_global;
166	
167	    std::vector<long long> estimated_weights(N_items_global);
168	
169	    int k_pivots_chosen = (N_items_global > 0) ? 1 : 0;
170	    if (N_items_global > 1) { 
171	        for (int cur_k_val = N_items_global; cur_k_val >= 1; --cur_k_val) {
172	            if (calculate_estimated_query_cost(N_items_global, cur_k_val) <= Q_total_global) {
173	                k_pivots_chosen = cur_k_val;
174	                break;
175	            }
176	        }
177	    }
178	    k_pivots_chosen = std::min(k_pivots_chosen, N_items_global); 
179	    if (N_items_global == 0) k_pivots_chosen = 0;
180	
181	
182	    std::vector<int> pivot_item_indices(k_pivots_chosen);
183	    if (k_pivots_chosen > 0) {
184	        std::vector<int> all_item_indices_temp(N_items_global);
185	        std::iota(all_item_indices_temp.begin(), all_item_indices_temp.end(), 0);
186	        std::shuffle(all_item_indices_temp.begin(), all_item_indices_temp.end(), rng_engine);
187	        for (int i = 0; i < k_pivots_chosen; ++i) pivot_item_indices[i] = all_item_indices_temp[i];
188	    }
189	    
190	    std::vector<int> sorted_pivot_item_indices = pivot_item_indices;
191	
192	    // Factors from previous attempt (more aggressive & symmetric):
193	    const int FACTOR_GT_NUM = 200; 
194	    const int FACTOR_LT_NUM = 50;  
195	    const int FACTOR_XJ_FALLBACK_NUM = 100; 
196	
197	    if (k_pivots_chosen == 0) { 
198	        for (int i = 0; i < N_items_global; ++i) estimated_weights[i] = BASE_WEIGHT;
199	    } else if (k_pivots_chosen == 1) { 
200	        estimated_weights[pivot_item_indices[0]] = BASE_WEIGHT;
201	        for (int i = 0; i < N_items_global; ++i) {
202	            if (i == pivot_item_indices[0]) continue;
203	            char res = compare_single_items(i, pivot_item_indices[0]);
204	            if (res == '=') estimated_weights[i] = BASE_WEIGHT;
205	            else if (res == '<') estimated_weights[i] = std::max(1LL, BASE_WEIGHT * FACTOR_LT_NUM / 100); 
206	            else estimated_weights[i] = std::max(1LL, BASE_WEIGHT * FACTOR_GT_NUM / 100);
207	        }
208	    } else { // k_pivots_chosen >= 2
209	        merge_sort_items(sorted_pivot_item_indices, 0, k_pivots_chosen - 1);
210	        
211	        int p0_idx = sorted_pivot_item_indices[0];
212	        estimated_weights[p0_idx] = BASE_WEIGHT;
213	        
214	        int p1_idx = sorted_pivot_item_indices[1];
215	        char res_p1_vs_p0 = compare_single_items(p1_idx, p0_idx);
216	
217	        if (res_p1_vs_p0 == '=') {
218	            estimated_weights[p1_idx] = estimated_weights[p0_idx];
219	        } else if (res_p1_vs_p0 == '<') { 
220	            estimated_weights[p1_idx] = std::max(1LL, estimated_weights[p0_idx] * FACTOR_LT_NUM / 100);
221	        } else { 
222	            estimated_weights[p1_idx] = std::max(1LL, estimated_weights[p0_idx] * FACTOR_GT_NUM / 100); 
223	        }
224	        // Ensure monotonicity and strictness if comparison was strict
225	        if (estimated_weights[p1_idx] < estimated_weights[p0_idx]) { 
226	             estimated_weights[p1_idx] = estimated_weights[p0_idx];
227	        }
228	        if (res_p1_vs_p0 == '>' && estimated_weights[p1_idx] == estimated_weights[p0_idx]) { 
229	             estimated_weights[p1_idx] = estimated_weights[p0_idx] + 1;
230	        }
231	
232	        const long long MAX_XJ_INITIAL_HIGH_BOUND = BASE_WEIGHT * (1LL * N_items_global / std::max(1, D_groups_global) + 10); // Increased +5 to +10 for safety margin
233	
234	        for (int j = 2; j < k_pivots_chosen; ++j) {
235	            int current_pivot_idx = sorted_pivot_item_indices[j];
236	            int prev_pivot_idx = sorted_pivot_item_indices[j-1];
237	
238	            char res_curr_vs_prev = compare_single_items(current_pivot_idx, prev_pivot_idx);
239	            if (res_curr_vs_prev == '=') {
240	                estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx];
241	            } else if (res_curr_vs_prev == '<') { 
242	                estimated_weights[current_pivot_idx] = std::max(1LL, estimated_weights[prev_pivot_idx] * FACTOR_LT_NUM / 100);
243	            } else { 
244	                long long X_low_bound_val = 1; 
245	                long long X_high_bound_val = MAX_XJ_INITIAL_HIGH_BOUND; 
246	                bool x_low_modified = false;
247	                bool x_high_modified = false;
248	
249	                int s_search_low_arr_idx = 0, s_search_high_arr_idx = j - 2;
250	                
251	                int num_s_candidates = (s_search_high_arr_idx - s_search_low_arr_idx + 1);
252	                int queries_for_this_Xj = 0;
253	                if (num_s_candidates > 0) {
254	                     queries_for_this_Xj = static_cast<int>(std::ceil(estimate_log2(static_cast<double>(num_s_candidates))));
255	                     if (num_s_candidates == 1) queries_for_this_Xj = 1; 
256	                }
257	
258	                for(int bs_iter = 0; bs_iter < queries_for_this_Xj && queries_made < Q_total_global; ++bs_iter) {
259	                    if (s_search_low_arr_idx > s_search_high_arr_idx) break; 
260	                    int s_mid_arr_idx = s_search_low_arr_idx + (s_search_high_arr_idx - s_search_low_arr_idx) / 2;
261	                    int item_s_aux_idx = sorted_pivot_item_indices[s_mid_arr_idx];
262	                    
263	                    // Skip if s_aux is same as prev_pivot_idx; R items must be distinct for query.
264	                    // This should not happen if s_aux is chosen from p0...p_{j-2} and prev_pivot is p_{j-1}.
265	                    // if (item_s_aux_idx == prev_pivot_idx) continue; // Should not be necessary
266	                                        
267	                    char res_1v2 = compare_1v2_items_specific(current_pivot_idx, prev_pivot_idx, item_s_aux_idx);
268	
269	                    if (res_1v2 == '=') { 
270	                        X_low_bound_val = X_high_bound_val = estimated_weights[item_s_aux_idx];
271	                        x_low_modified = x_high_modified = true;
272	                        break; 
273	                    } else if (res_1v2 == '<') { 
274	                        X_high_bound_val = estimated_weights[item_s_aux_idx];
275	                        x_high_modified = true;
276	                        s_search_high_arr_idx = s_mid_arr_idx - 1;
277	                    } else { // res_1v2 == '>'
278	                        X_low_bound_val = estimated_weights[item_s_aux_idx];
279	                        x_low_modified = true;
280	                        s_search_low_arr_idx = s_mid_arr_idx + 1;
281	                    }
282	                }
283	                
284	                long long estimated_X_j;
285	                if (x_low_modified && !x_high_modified) { // X_j > X_low_bound_val (max s_aux smaller than X_j)
286	                    estimated_X_j = X_low_bound_val * FACTOR_GT_NUM / 100;
287	                } else if (!x_low_modified && x_high_modified) { // X_j < X_high_bound_val (min s_aux larger than X_j)
288	                    estimated_X_j = X_high_bound_val * FACTOR_LT_NUM / 100;
289	                } else if (x_low_modified && x_high_modified) { // X_j is bracketed
290	                    // Reverted to ARITHMETIC MEAN for X_j
291	                    estimated_X_j = (X_low_bound_val + X_high_bound_val) / 2;
292	                } else { // Fallback if binary search didn't narrow down X_j
293	                    estimated_X_j = estimated_weights[prev_pivot_idx] * FACTOR_XJ_FALLBACK_NUM / 100;
294	                    if (estimated_weights[prev_pivot_idx] > 0 && estimated_X_j == 0) estimated_X_j = 1; 
295	                    else if (estimated_weights[prev_pivot_idx] == 0) { 
296	                         estimated_X_j = std::max(1LL, BASE_WEIGHT * FACTOR_XJ_FALLBACK_NUM / 100);
297	                    }
298	                }
299	                estimated_X_j = std::max(1LL, estimated_X_j); 
300	                
301	                estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx] + estimated_X_j;
302	            }
303	            // Ensure monotonicity and strictness
304	            if(estimated_weights[current_pivot_idx] < estimated_weights[prev_pivot_idx]) {
305	                 estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx];
306	            }
307	            if (res_curr_vs_prev == '>' && estimated_weights[current_pivot_idx] == estimated_weights[prev_pivot_idx]) {
308	                estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx] + 1;
309	            }
310	        }
311	
312	        // Estimate weights for non-pivot items
313	        for (int i=0; i<N_items_global; ++i) {
314	            bool is_pivot_flag = false; 
315	            for(int p_idx_val=0; p_idx_val<k_pivots_chosen; ++p_idx_val) {
316	                if(sorted_pivot_item_indices[p_idx_val] == i) {
317	                    is_pivot_flag = true;
318	                    break;
319	                }
320	            }
321	            if (is_pivot_flag) continue; 
322	
323	            int bs_low_arr_idx = 0, bs_high_arr_idx = k_pivots_chosen - 1;
324	            int found_pivot_idx_for_eq = -1; 
325	
326	            while(bs_low_arr_idx <= bs_high_arr_idx) {
327	                if (queries_made >= Q_total_global && found_pivot_idx_for_eq == -1) break; // Stop if out of queries unless already found exact
328	                int mid_p_arr_idx = bs_low_arr_idx + (bs_high_arr_idx - bs_low_arr_idx) / 2;
329	                char res_item_vs_p = compare_single_items(i, sorted_pivot_item_indices[mid_p_arr_idx]);
330	
331	                if (res_item_vs_p == '=') {
332	                    found_pivot_idx_for_eq = mid_p_arr_idx;
333	                    break;
334	                } else if (res_item_vs_p == '<') {
335	                    bs_high_arr_idx = mid_p_arr_idx - 1;
336	                } else { 
337	                    bs_low_arr_idx = mid_p_arr_idx + 1;
338	                }
339	            }
340	            
341	            if (found_pivot_idx_for_eq != -1) { 
342	                estimated_weights[i] = estimated_weights[sorted_pivot_item_indices[found_pivot_idx_for_eq]];
343	                continue;
344	            }
345	            
346	            int insert_pos_arr_idx = bs_low_arr_idx; 
347	            
348	            if (insert_pos_arr_idx == 0) { // Smaller than p0
349	                long long w_p0 = estimated_weights[sorted_pivot_item_indices[0]];
350	                if (k_pivots_chosen >= 2) { 
351	                    long long w_p1 = estimated_weights[sorted_pivot_item_indices[1]];
352	                    // Ensure w_p1 != 0 before division, and w_p0 must be < w_p1 for this extrapolation to make sense
353	                    if (w_p1 > w_p0 && w_p0 > 0 && w_p1 != 0) { // w_p1 should not be 0 if weights are >=1
354	                         estimated_weights[i] = std::max(1LL, w_p0 * w_p0 / w_p1); 
355	                    } else { 
356	                        estimated_weights[i] = std::max(1LL, w_p0 * FACTOR_LT_NUM / 100);
357	                    }
358	                } else { // Only p0 exists
359	                     estimated_weights[i] = std::max(1LL, w_p0 * FACTOR_LT_NUM / 100);
360	                }
361	            } else if (insert_pos_arr_idx == k_pivots_chosen) { // Larger than p_{k-1}
362	                long long w_pk_1 = estimated_weights[sorted_pivot_item_indices[k_pivots_chosen-1]];
363	                 if (k_pivots_chosen >= 2) { 
364	                    long long w_pk_2 = estimated_weights[sorted_pivot_item_indices[k_pivots_chosen-2]];
365	                    // Ensure w_pk_2 != 0 and w_pk_2 < w_pk_1
366	                    if (w_pk_1 > w_pk_2 && w_pk_2 > 0 && w_pk_2 != 0) { // w_pk_2 should not be 0
367	                        estimated_weights[i] = std::max(1LL, w_pk_1 * w_pk_1 / w_pk_2); 
368	                    } else { 
369	                        estimated_weights[i] = std::max(1LL, w_pk_1 * FACTOR_GT_NUM / 100);
370	                    }
371	                 } else { // Only p0 exists (which is p_{k-1} here)
372	                     estimated_weights[i] = std::max(1LL, w_pk_1 * FACTOR_GT_NUM / 100);
373	                 }
374	            } else { // Between p_{idx-1} and p_{idx}
375	                long long w_prev_p = estimated_weights[sorted_pivot_item_indices[insert_pos_arr_idx-1]];
376	                long long w_next_p = estimated_weights[sorted_pivot_item_indices[insert_pos_arr_idx]];
377	                // Geometric mean for interpolation is generally preferred for exponential-like data
378	                if (w_prev_p > 0 && w_next_p > 0) { 
379	                    estimated_weights[i] = static_cast<long long>(std::sqrt(static_cast<double>(w_prev_p) * w_next_p));
380	                } else { // Fallback for safety or if one weight is zero (should be >=1)
381	                    estimated_weights[i] = (w_prev_p + w_next_p) / 2;
382	                }
383	                // Ensure estimate is within the bounds of the two pivots it's between
384	                estimated_weights[i] = std::max(w_prev_p, estimated_weights[i]);
385	                estimated_weights[i] = std::min(w_next_p, estimated_weights[i]);
386	            }
387	            if (estimated_weights[i] <=0) estimated_weights[i] = 1; 
388	        }
389	    }
390	
391	    // Final check: all weights must be at least 1.
392	    for(int i=0; i<N_items_global; ++i) {
393	        if (estimated_weights[i] <= 0) { 
394	            // This state indicates a flaw in estimation logic or extreme case.
395	            // Fallback to a reasonable default like BASE_WEIGHT or 1.
396	            // Previous version used BASE_WEIGHT. Smallest possible is 1.
397	            // Using 1 might be safer if other weights are also small.
398	            // However, if most are large, BASE_WEIGHT might be better.
399	            // Sticking to previous fallback.
400	            estimated_weights[i] = BASE_WEIGHT; 
401	        }
402	    }
403	    
404	    // Exhaust remaining queries
405	    int dummy_item_0_idx = 0;
406	    int dummy_item_1_idx = 1; 
407	    // N_items_global >= 30, so 0 and 1 are valid and distinct indices.
408	    while(queries_made < Q_total_global) {
409	        perform_query_actual({dummy_item_0_idx}, {dummy_item_1_idx});
410	        // Cycle one of the items to make queries slightly different, though not critical for correctness
411	        dummy_item_1_idx = (dummy_item_1_idx + 1) % N_items_global;
412	        if (dummy_item_1_idx == dummy_item_0_idx) { // Ensure distinctness
413	            dummy_item_1_idx = (dummy_item_1_idx + 1) % N_items_global;
414	        }
415	    }
416	    
417	    // --- Assignment Phase: Greedy followed by Simulated Annealing ---
418	    std::vector<int> assignment_array(N_items_global);
419	    std::vector<long long> group_sums_array(D_groups_global, 0);
420	    long long total_sum_est_val = 0;
421	
422	    std::vector<std::vector<int>> group_items_indices(D_groups_global);
423	    std::vector<int> item_pos_in_group_vector(N_items_global); 
424	
425	    std::vector<std::pair<long long, int>> items_sorted_for_greedy(N_items_global);
426	    for(int i=0; i<N_items_global; ++i) {
427	        items_sorted_for_greedy[i] = {-estimated_weights[i], i}; 
428	    }
429	    std::sort(items_sorted_for_greedy.begin(), items_sorted_for_greedy.end());
