input.content:
# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <cmath>
#include <set>
#include <map>
#include <chrono>
#include <random>

std::chrono::steady_clock::time_point program_start_time;
std::chrono::milliseconds time_limit_ms(1850);

int N_items_global, D_groups_global, Q_total_global;
int queries_made = 0;

std::map<std::pair<int, int>, char> comparison_cache;
std::mt19937 rng_engine;

char perform_query_actual(const std::vector<int>& L_items, const std::vector<int>& R_items) {
    queries_made++;
    std::cout << L_items.size() << " " << R_items.size();
    for (int item_idx : L_items) std::cout << " " << item_idx;
    for (int item_idx : R_items) std::cout << " " << item_idx;
    std::cout << std::endl;
    char result_char;
    std::cin >> result_char;
    return result_char;
}

char compare_single_items(int a, int b) {
    if (a == b) return '=';
    std::pair<int, int> key = {std::min(a, b), std::max(a, b)};
    auto it = comparison_cache.find(key);
    if (it != comparison_cache.end()) {
        char cached = it->second;
        if (a == key.first) return cached;
        return (cached == '<' ? '>' : (cached == '>' ? '<' : '='));
    }
    if (queries_made >= Q_total_global) return '=';
    char res = perform_query_actual({a}, {b});
    if (a < b) comparison_cache[key] = res;
    else {
        char rev = (res == '<' ? '>' : (res == '>' ? '<' : '='));
        comparison_cache[key] = rev;
    }
    return res;
}

void merge_sort_merge(std::vector<int>& items, int left, int mid, int right) {
    int n1 = mid - left + 1, n2 = right - mid;
    std::vector<int> L(n1), R(n2);
    for (int i = 0; i < n1; i++) L[i] = items[left + i];
    for (int j = 0; j < n2; j++) R[j] = items[mid + 1 + j];
    int i = 0, j = 0, k = left;
    while (i < n1 && j < n2) {
        char cmp = compare_single_items(L[i], R[j]);
        if (cmp == '<' || cmp == '=') items[k++] = L[i++];
        else items[k++] = R[j++];
    }
    while (i < n1) items[k++] = L[i++];
    while (j < n2) items[k++] = R[j++];
}

void merge_sort(std::vector<int>& items, int left, int right) {
    if (left < right) {
        int mid = left + (right - left) / 2;
        merge_sort(items, left, mid);
        merge_sort(items, mid + 1, right);
        merge_sort_merge(items, left, mid, right);
    }
}

int estimate_sort_cost(int n) {
    if (n <= 1) return 0;
    return (int)std::ceil(n * std::log2((double)n));
}

double compute_order_stat_weight(int rank_1indexed, int n_total) {
    // E[X_{(k:n)}] = (1/lambda) * sum_{j=1}^{k} 1/(n-j+1)
    // lambda = 10^-5, so 1/lambda = 100000
    double sum = 0.0;
    for (int j = 1; j <= rank_1indexed; j++) {
        sum += 1.0 / (n_total - j + 1);
    }
    return 100000.0 * sum;
}

