        }
    }
    k_pivots = std::max(1, std::min(k_pivots, N_items_global));

    std::vector<int> all_items(N_items_global);
    std::iota(all_items.begin(), all_items.end(), 0);
    std::shuffle(all_items.begin(), all_items.end(), rng_engine);

    std::vector<int> pivot_items(all_items.begin(), all_items.begin() + k_pivots);
    std::vector<int> non_pivot_items(all_items.begin() + k_pivots, all_items.end());

    // Sort pivot items (ascending)
    if (k_pivots > 1) {
        merge_sort(pivot_items, 0, k_pivots - 1);
    }

    // Binary search non-pivot items among sorted pivots
    std::vector<int> item_insert_pos(N_items_global, 0);
    for (int item : non_pivot_items) {
        int lo = 0, hi = k_pivots - 1;
        int insert_pos = k_pivots;

        while (lo <= hi && queries_made < Q_total_global) {
            int mid = lo + (hi - lo) / 2;
            char cmp = compare_single_items(item, pivot_items[mid]);
            if (cmp == '=') {
                insert_pos = mid;
                break;
            } else if (cmp == '<') {
                insert_pos = mid;
                hi = mid - 1;
            } else {
                lo = mid + 1;
            }
        }
        if (lo > hi && insert_pos == k_pivots) {
            insert_pos = lo;
        }
        item_insert_pos[item] = insert_pos;
    }

    // Group non-pivot items by bin
    std::vector<std::vector<int>> bins(k_pivots + 1);
    for (int item : non_pivot_items) {
        bins[item_insert_pos[item]].push_back(item);
    }

    // Build complete ordering: bins interleaved with pivots
    // Items within unsorted bins share the same rank (midpoint)
    std::vector<int> fully_ordered;
    fully_ordered.reserve(N_items_global);
    for (int b = 0; b <= k_pivots; b++) {
        for (int item : bins[b]) fully_ordered.push_back(item);
        if (b < k_pivots) fully_ordered.push_back(pivot_items[b]);
    }

    // Assign weights using order statistics of Exp(10^-5)
    // Items in same bin get the average weight across their rank range
    std::vector<double> estimated_weights(N_items_global);
    int rank = 1;
    for (int b = 0; b <= k_pivots; b++) {
        int bin_size = bins[b].size();
        if (bin_size > 0) {
            // Compute average order stat weight for ranks [rank, rank+bin_size-1]
            double avg_w = 0.0;
            for (int r = rank; r < rank + bin_size; r++) {
                avg_w += compute_order_stat_weight(r, N_items_global);
            }
            avg_w /= bin_size;
            for (int item : bins[b]) {
                estimated_weights[item] = avg_w;
            }
            rank += bin_size;
        }
        if (b < k_pivots) {
            estimated_weights[pivot_items[b]] = compute_order_stat_weight(rank, N_items_global);
            rank++;
        }
    }

    // Ensure all weights at least 1
    for (int i = 0; i < N_items_global; i++) {
        if (estimated_weights[i] < 1.0) estimated_weights[i] = 1.0;
    }

    // Exhaust remaining queries
    int d0 = 0, d1 = 1;
    while (queries_made < Q_total_global) {
        perform_query_actual({d0}, {d1});
        d1 = (d1 + 1) % N_items_global;
        if (d1 == d0) d1 = (d1 + 1) % N_items_global;
    }

    // --- Assignment: LPT Greedy + SA ---
    std::vector<int> assignment(N_items_global);
    std::vector<double> group_sums(D_groups_global, 0.0);
    double total_sum = 0.0;

    std::vector<std::vector<int>> group_items(D_groups_global);
    std::vector<int> item_pos_in_group(N_items_global);

    // Sort items descending by weight for LPT
    std::vector<std::pair<double, int>> items_by_weight(N_items_global);
    for (int i = 0; i < N_items_global; i++) {
        items_by_weight[i] = {-estimated_weights[i], i};
        total_sum += estimated_weights[i];
    }
    std::sort(items_by_weight.begin(), items_by_weight.end());

    for (int i = 0; i < N_items_global; i++) {
        int item = items_by_weight[i].second;
        double w = estimated_weights[item];
        int best_grp = 0;
        double min_sum = group_sums[0];
        for (int j = 1; j < D_groups_global; j++) {
            if (group_sums[j] < min_sum) {
                min_sum = group_sums[j];
                best_grp = j;
            }
        }
        assignment[item] = best_grp;
        group_sums[best_grp] += w;
        group_items[best_grp].push_back(item);
        item_pos_in_group[item] = group_items[best_grp].size() - 1;
    }

    double sum_sq = 0.0;
    for (double s : group_sums) sum_sq += s * s;
    double current_var = calculate_variance_from_sums(sum_sq, total_sum, D_groups_global);

    // SA parameters
    double T = std::max(1.0, current_var * 0.25);
    if (current_var < 1e-9) T = std::max(1.0, total_sum / std::max(1, N_items_global) * 0.1);
    if (D_groups_global <= 1) T = 0;
    double cool_rate = 0.9999;

    std::uniform_real_distribution<double> unif(0.0, 1.0);
    int sa_iters = 0;
    const int CHECK_TIME_INTERVAL = 256;
    int no_improve = 0;

    while (D_groups_global > 1 && N_items_global > 0) {
        sa_iters++;
        if (sa_iters % CHECK_TIME_INTERVAL == 0) {
            auto now = std::chrono::steady_clock::now();
            if (std::chrono::duration_cast<std::chrono::milliseconds>(now - program_start_time) >= time_limit_ms) break;
            T *= cool_rate;
            if (no_improve > N_items_global * 15 && T < current_var * 0.05 && current_var > 1.0) {
                T = std::max(1.0, current_var * 0.1);
                no_improve = 0;
            }
        }
        if (T < 1e-12 && current_var < 1.0 + 1e-9) break;
        if (T < 1e-15) T = 1e-15;

        bool try_swap = (rng_engine() % 3 == 0);

        if (!try_swap) {
            int item = rng_engine() % N_items_global;
            int old_grp = assignment[item];
            int new_grp = rng_engine() % D_groups_global;
            while (new_grp == old_grp) new_grp = rng_engine() % D_groups_global;

            double w = estimated_weights[item];
            double old_s_A = group_sums[old_grp], old_s_B = group_sums[new_grp];
            double new_s_A = old_s_A - w, new_s_B = old_s_B + w;

            double new_sum_sq = sum_sq - old_s_A*old_s_A - old_s_B*old_s_B + new_s_A*new_s_A + new_s_B*new_s_B;
            double new_var = calculate_variance_from_sums(new_sum_sq, total_sum, D_groups_global);
            double delta = new_var - current_var;

            if (delta < 0 || (T > 1e-12 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var;
                sum_sq = new_sum_sq;
                group_sums[old_grp] = new_s_A;
                group_sums[new_grp] = new_s_B;
                assignment[item] = new_grp;

                int pos = item_pos_in_group[item];
                if (!group_items[old_grp].empty()) {
                    int last = group_items[old_grp].back();
                    if (item != last) {
                        group_items[old_grp][pos] = last;
                        item_pos_in_group[last] = pos;
                    }
                    group_items[old_grp].pop_back();
                }
                group_items[new_grp].push_back(item);
                item_pos_in_group[item] = group_items[new_grp].size() - 1;
                if (delta < -1e-9) no_improve = 0; else no_improve++;
            } else {
                no_improve++;
            }
        } else {
            int g1 = rng_engine() % D_groups_global;
            int g2 = rng_engine() % D_groups_global;
            while (g2 == g1) g2 = rng_engine() % D_groups_global;
            if (group_items[g1].empty() || group_items[g2].empty()) continue;

            int item1 = group_items[g1][rng_engine() % group_items[g1].size()];
            int item2 = group_items[g2][rng_engine() % group_items[g2].size()];

            double w1 = estimated_weights[item1], w2 = estimated_weights[item2];
            double old_s1 = group_sums[g1], old_s2 = group_sums[g2];
            double new_s1 = old_s1 - w1 + w2, new_s2 = old_s2 - w2 + w1;

            double new_sum_sq = sum_sq - old_s1*old_s1 - old_s2*old_s2 + new_s1*new_s1 + new_s2*new_s2;
            double new_var = calculate_variance_from_sums(new_sum_sq, total_sum, D_groups_global);
            double delta = new_var - current_var;

            if (delta < 0 || (T > 1e-12 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var;
                sum_sq = new_sum_sq;
                group_sums[g1] = new_s1;
                group_sums[g2] = new_s2;
                assignment[item1] = g2;
                assignment[item2] = g1;

                int pos1 = item_pos_in_group[item1];
                int back1 = group_items[g1].back();
                if (item1 != back1) {
                    group_items[g1][pos1] = back1;
                    item_pos_in_group[back1] = pos1;
                }
                group_items[g1].pop_back();

                int pos2 = item_pos_in_group[item2];
                int back2 = group_items[g2].back();
                if (item2 != back2) {
                    group_items[g2][pos2] = back2;
                    item_pos_in_group[back2] = pos2;
                }
                group_items[g2].pop_back();

                group_items[g2].push_back(item1);
                item_pos_in_group[item1] = group_items[g2].size() - 1;
                group_items[g1].push_back(item2);
                item_pos_in_group[item2] = group_items[g1].size() - 1;
                if (delta < -1e-9) no_improve = 0; else no_improve++;
            } else {
                no_improve++;
            }
        }
    }

    for (int i = 0; i < N_items_global; i++) {
        std::cout << assignment[i] << (i == N_items_global - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}
